 	err = manager.Uninstall(extensions[0].Id)
 	require.NoError(t, err)

 	// List installed extensions (expect 0)
 	installed, err = manager.ListInstalled()
 	require.NoError(t, err)
 	require.NotNil(t, installed)
 	require.Equal(t, 0, len(installed))
 }

