155. func (cli *CLI) RunCommandWithStdIn(ctx context.Context, stdin string, args ...string) (*CliResult, error) {
156. 	description := "azd " + strings.Join(args, " ") + " in " + cli.WorkingDirectory
157. 
158. 	/* #nosec G204 - Subprocess launched with a potential tainted input or cmd arguments false positive */
159. 	cmd := osexec.CommandContext(ctx, cli.AzdPath, args...)
160. 	if cli.WorkingDirectory != "" {
161. 		cmd.Dir = cli.WorkingDirectory
162. 	}
163. 
164. 	if stdin != "" {
165. 		cmd.Stdin = strings.NewReader(stdin)
166. 	} else {
167. 		cmd.Stdin = os.Stdin
168. 	}
169. 
170. 	cmd.Env = cli.Env
171. 
172. 	// Disable agent detection in the child azd process so that the test's parent process tree
173. 	// (which may include an AI agent like Copilot CLI) does not auto-enable --no-prompt mode.
174. 	// This ensures functional tests that pipe stdin for interactive prompts work correctly.
175. 	// When cmd.Env is nil, the child inherits the parent's environment. We must preserve that
176. 	// by explicitly copying os.Environ() before appending.
177. 	if cmd.Env == nil {
178. 		cmd.Env = os.Environ()
179. 	}
180. 	cmd.Env = append(cmd.Env, agentdetect.DisableAgentDetectEnvVar+"=1")
181. 
182. 	// Collect all PATH variables, appending in the order it was added, to form a single PATH variable
183. 	pathString := ostest.CombinedPaths(cmd.Env)
184. 
185. 	if len(pathString) > 0 {
186. 		cmd.Env = append(cmd.Env, pathString)
187. 	}
188. 
189. 	// we run a background goroutine to report a heartbeat in the logs while the command
190. 	// is still running. This makes it easy to see what's still in progress if we hit a timeout.
191. 	done := make(chan struct{})
192. 	go func() {
193. 		cli.heartbeat(description, done)
194. 	}()
195. 	defer func() {
196. 		done <- struct{}{}
197. 	}()
198. 
199. 	now := time.Now()
200. 	stdOutLogger := &logWriter{t: cli.T, prefix: "[stdout] ", initialTime: now}
201. 	stdErrLogger := &logWriter{t: cli.T, prefix: "[stderr] ", initialTime: now}
202. 
203. 	var stderr, stdout bytes.Buffer
204. 	cmd.Stderr = io.MultiWriter(&stderr, stdErrLogger)
205. 	cmd.Stdout = io.MultiWriter(&stdout, stdOutLogger)
206. 	err := cmd.Start()
207. 	if err != nil {
208. 		return nil, fmt.Errorf("failed to start command '%s': %w", description, err)
209. 	}
210. 
211. 	err = cmd.Wait()
212. 	result := &CliResult{
213. 		ExitCode: cmd.ProcessState.ExitCode(),
214. 		Stdout:   stdout.String(),
215. 		Stderr:   stderr.String(),
216. 	}
217. 
218. 	if errors.Is(ctx.Err(), context.DeadlineExceeded) {
219. 		return result, fmt.Errorf("command '%s' timed out: %w", description, err)
220. 	}
221. 
222. 	if errors.Is(ctx.Err(), context.Canceled) {
223. 		// bubble up errors due to cancellation with their output, and let the caller
224. 		// decide how to handle it.
225. 		return result, ctx.Err()
226. 	}
227. 
228. 	if err != nil {
229. 		return result, fmt.Errorf("command '%s' had non-zero exit code: %w", description, err)
230. 	}
231. 
232. 	return result, nil
233. }
